Description
The following example shows the use of the RESET pragma or directive with class variables and methods. A variable declared in a class must be a public static variable in the class and can have the RESET pragma specified for the variable in a method of the class, or after an object of the class has been created in th...
class bar {
public:
    static int a; // class level static; must be public
    int al;    // class-level non-static; must be public
    bar(...) {
    // #pragma reset does not work here for a or al
    }
    // this is the function that is called in the top
    void run(...) {
    // #pragma reset does not work here for non-static variable al
    // but does work for static variable a
    #pragma reset variable=a
    }
};
static int c; // file level
int d; // file level
void top(...) {
#pragma HLS top
    static int b; // function level
    bar t;
    static bar s;

    // #pragma reset works here for b, c and d, as well as t and s members
    // except for t.al because it is not static
    #pragma reset variable=b
    #pragma reset variable=c
    #pragma reset variable=d
    #pragma reset variable=t.a
    #pragma reset variable=s.a
    #pragma reset variable=s.al
    t.run(...);
    s.run(...);
}

